mapper.select:
select YYYYMM, SEL_CODE, SITE as SITE_ORG, CASE WHEN SITE='HQ' then '본사' WHEN site='VN' then 'VINA' end as SITE, 코스트센터, 코스트센터분류, 코스트센터유형, 계정코드, 계정과목, 비용구분, 차변금액, 대변금액 from DOI_DEPT_COST where 1=1
and yyyymm = #{yyyymm}
and site = #{site}
order BY 코스트센터;

DROP TABLE IF EXISTS #TempTable1;

CREATE TABLE #TempTable1 (
	yyyymm varchar(6) COLLATE Korean_Wansung_CI_AS NOT NULL,
	sel_code varchar(6) COLLATE Korean_Wansung_CI_AS NOT NULL,
	site varchar(4) COLLATE Korean_Wansung_CI_AS NOT NULL,
	코스트센터 nvarchar(15) COLLATE Korean_Wansung_CI_AS NOT NULL,
	코스트센터분류 nvarchar(12) COLLATE Korean_Wansung_CI_AS NULL,
	코스트센터유형 nvarchar(12) COLLATE Korean_Wansung_CI_AS NULL,
	계정코드 varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
	계정과목 nvarchar(30) COLLATE Korean_Wansung_CI_AS NULL,
	비용구분 nvarchar(8) COLLATE Korean_Wansung_CI_AS NULL,
	차변금액 bigint NULL,
	대변금액 bigint NULL
);

INSERT INTO #TempTable1
(
YYYYMM
, SEL_CODE
, SITE
, 코스트센터
, 코스트센터분류
, 코스트센터유형
, 계정코드
, 계정과목
, 비용구분
, 차변금액
, 대변금액
)
VALUES

	(
	#{item.field2}
	, #{item.field3}
	, #{item.field4}
	, #{item.field5}
	, #{item.field6}
	, #{item.field7}
	, #{item.field8}
	, #{item.field9}
	, #{item.field10}
	, #{item.field11}
	, #{item.field12}
	)
;

SELECT * FROM #TempTable1 a
WHERE EXISTS (
	SELECT 1
	FROM DOI_DEPT_COST b
	WHERE 1=1
	AND b.yyyymm = a.yyyymm
	AND b.sel_code = a.sel_code
	AND b.site = a.site
	AND b.코스트센터 = a.코스트센터
	AND b.계정코드 = a.계정코드
);

mapper.insert:
CREATE TABLE #TempTable (
	seq_no INT IDENTITY (1, 1) NOT NULL,
	yyyymm varchar(6) COLLATE Korean_Wansung_CI_AS NOT NULL,
	sel_code varchar(6) COLLATE Korean_Wansung_CI_AS NOT NULL,
	site varchar(4) COLLATE Korean_Wansung_CI_AS NOT NULL,
	코스트센터 nvarchar(15) COLLATE Korean_Wansung_CI_AS NOT NULL,
	코스트센터분류 nvarchar(12) COLLATE Korean_Wansung_CI_AS NULL,
	코스트센터유형 nvarchar(12) COLLATE Korean_Wansung_CI_AS NULL,
	계정코드 varchar(10) COLLATE Korean_Wansung_CI_AS NOT NULL,
	계정과목 nvarchar(30) COLLATE Korean_Wansung_CI_AS NULL,
	비용구분 nvarchar(8) COLLATE Korean_Wansung_CI_AS NULL,
	차변금액 bigint NULL,
	대변금액 bigint NULL
);

