INSERT INTO DOI_DEPT_COST (yyyymm,sel_code,site,코스트센터,코스트센터분류,코스트센터유형,계정코드,계정과목,비용구분,차변금액,대변금액)
SELECT yyyymm,sel_code,site,코스트센터,코스트센터분류,코스트센터유형,계정코드,계정과목,비용구분,차변금액,대변금액
FROM (
	SELECT *, MAX(seq_no) over (partition by yyyymm,sel_code,site,코스트센터,계정코드) max_seq_no FROM #TempTable
) A
WHERE 1=1
AND seq_no = max_seq_no
AND NOT EXISTS (
	SELECT 1
	FROM DOI_DEPT_COST b
	WHERE 1=1
	AND b.yyyymm = a.yyyymm
	AND b.sel_code = a.sel_code
	AND b.site = a.site
	AND b.코스트센터 = a.코스트센터
	AND b.계정코드 = a.계정코드
);

DROP TABLE #TempTable;

INSERT INTO DOI_DEPT_COST
(
YYYYMM
, SEL_CODE
, SITE
, 코스트센터
, 코스트센터분류
, 코스트센터유형
, 계정코드
, 계정과목
, 비용구분
, 차변금액
, 대변금액
)
VALUES
(
#{yyyymm}
, #{selCode}
, CASE WHEN #{site}='본사' Then 'HQ'  WHEN #{site}='VINA' then 'VN' else left(#{site},2) end
, #{코스트센터}
, #{코스트센터분류}
, #{코스트센터유형}
, #{계정코드}
, #{계정과목}
, #{비용구분}
, #{차변금액}
, #{대변금액}
);

mapper.delete:
DELETE FROM DOI_DEPT_COST
WHERE 1=1
and yyyymm = #{yyyymm}
and sel_code = #{selCode}
and site = #{siteOrg}
and 코스트센터 = #{코스트센터}
and 계정코드 = #{계정코드}

mapper.update:
UPDATE DOI_DEPT_COST
SET 코스트센터분류 = #{코스트센터분류}
, 코스트센터유형 = #{코스트센터유형}
, 계정과목 = #{계정과목}
, 비용구분 = #{비용구분}
, 차변금액 = #{차변금액}
, 대변금액 = #{대변금액}
WHERE 1=1
and yyyymm = #{yyyymm}
and SEL_CODE = #{selCode}
and site = #{siteOrg}
and 코스트센터 = #{코스트센터}
and 계정코드 = #{계정코드}
;
